class Solution:
    def numTilePossibilities(self, tiles):
        from collections import Counter
        counts = Counter(tiles)
        def dfs(cnt):
            total = 0
            for ch in list(cnt.keys()):
                if cnt[ch] > 0:
                    total += 1
                    cnt[ch] -= 1
                    total += dfs(cnt)
                    cnt[ch] += 1
            return total
        return dfs(counts)

