var numTilePossibilities = function(tiles) {
    const counts = new Map();
    for (const ch of tiles) counts.set(ch, (counts.get(ch) || 0) + 1);
    function dfs() {
        let total = 0;
        for (const ch of counts.keys()) {
            if (counts.get(ch) > 0) {
                total += 1;
                counts.set(ch, counts.get(ch) - 1);
                total += dfs();
                counts.set(ch, counts.get(ch) + 1);
            }
        }
        return total;
    }
    return dfs();
};
